const config = $('Configuration (EDIT ME)').first().json;
const baseUrl = String(config.sellfUrl || '').replace(/\/+$/, '');
const logs = ($input.first().json.data) || [];
if (!Array.isArray(logs) || logs.length === 0) return [];

const byEndpoint = new Map();
for (const l of logs) {
  const key = l.endpoint_id || 'unknown';
  const agg = byEndpoint.get(key) || { lines: [], retries: [] };
  agg.lines.push(`\u2022 ${l.event_type || 'unknown'} @ ${l.created_at || ''} (${l.http_status || 'timeout'})`);
  agg.retries.push({ retryUrl: `${baseUrl}/api/v1/webhooks/logs/${l.id}/retry` });
  byEndpoint.set(key, agg);
}

return [...byEndpoint.entries()].map(([endpointId, agg]) => ({ json: {
  endpointId,
  failedCount: agg.lines.length,
  retries: agg.retries.slice(0, 5),
  alertMessage: `\u{1F534} *${agg.lines.length} failed webhook delivery(ies)*\nEndpoint: ${endpointId}\n\n${agg.lines.slice(0, 5).join('\n')}`,
} }));

const out = [];
for (const item of $input.all()) {
  for (const r of (item.json.retries || [])) out.push({ json: r });
}
return out;
